enum ResourceOffset {
  cpu_resource_offset(0),
  cuda_resource_offset(10000),
  dml_resource_offset(20000),
  migraphx_resource_offset(30000),
  custom_ep_resource_offset(10000000);

  final int value;
  const ResourceOffset(this.value);

  static ResourceOffset fromValue(int value) => switch (value) {
    0 => cpu_resource_offset,
    10000 => cuda_resource_offset,
    20000 => dml_resource_offset,
    30000 => migraphx_resource_offset,
    10000000 => custom_ep_resource_offset,
    _ => throw ArgumentError('Unknown value for ResourceOffset: $value'),
  };
}

