  /// \snippet{doc} snippets.dox OrtStatus Return Value
  ///
  /// \since Version 1.23.
  external ffi.Pointer<
    ffi.NativeFunction<
      OrtStatusPtr Function(
        ffi.Pointer<OrtEp> this_ptr,
