/// \brief The event category for profiling events reported by an execution provider.
///
/// \since Version 1.25.
enum OrtProfilingEventCategory {
  /// < Session-level event
  OrtProfilingEventCategory_SESSION(0),

  /// < Node-level event
  OrtProfilingEventCategory_NODE(1),

  /// < Kernel-level event
  OrtProfilingEventCategory_KERNEL(2),

  /// < API-level event
  OrtProfilingEventCategory_API(3);

  final int value;
  const OrtProfilingEventCategory(this.value);

  static OrtProfilingEventCategory fromValue(int value) => switch (value) {
    0 => OrtProfilingEventCategory_SESSION,
    1 => OrtProfilingEventCategory_NODE,
    2 => OrtProfilingEventCategory_KERNEL,
    3 => OrtProfilingEventCategory_API,
    _ => throw ArgumentError(
      'Unknown value for OrtProfilingEventCategory: $value',
    ),
  };
}

